# mttx_calculator.py - compute MTTD, MTTA, MTTR from incident records
from dataclasses import dataclass
from datetime import datetime, timedelta
from typing import List, Optional
from statistics import mean, median, stdev
import json


@dataclass
class IncidentTimeline:
    incident_id: str
    severity: str
    first_anomaly_time: datetime   # when the failure first occurred
    alert_fire_time: datetime      # when the monitoring alert fired
    ic_engaged_time: datetime      # when IC acknowledged and started response
    resolution_time: datetime      # when service was restored

    @property
    def mttd_minutes(self) -> float:
        # Mean Time to Detect: anomaly -> alert
        return (self.alert_fire_time - self.first_anomaly_time).total_seconds() / 60

    @property
    def mtta_minutes(self) -> float:
        # Mean Time to Acknowledge: alert -> IC engaged
        return (self.ic_engaged_time - self.alert_fire_time).total_seconds() / 60

    @property
    def mttr_minutes(self) -> float:
        # Mean Time to Resolve: anomaly -> resolution
        return (self.resolution_time - self.first_anomaly_time).total_seconds() / 60

    @property
    def mtte_minutes(self) -> float:
        # Mean Time to Engage+Fix: IC engaged -> resolution
        return (self.resolution_time - self.ic_engaged_time).total_seconds() / 60


def compute_mttx_report(
    incidents: List[IncidentTimeline],
    period_label: str = 'Q3 2026',
) -> dict:
    if not incidents:
        return {'period': period_label, 'count': 0}

    mttd_vals = [i.mttd_minutes for i in incidents]
    mtta_vals = [i.mtta_minutes for i in incidents]
    mttr_vals = [i.mttr_minutes for i in incidents]

    def stats(vals):
        return {
            'mean_min': round(mean(vals), 1),
            'median_min': round(median(vals), 1),
            'p95_min': round(sorted(vals)[int(len(vals) * 0.95)], 1),
            'stdev_min': round(stdev(vals), 1) if len(vals) > 1 else 0,
        }

    return {
        'period': period_label,
        'incident_count': len(incidents),
        'mttd': stats(mttd_vals),
        'mtta': stats(mtta_vals),
        'mttr': stats(mttr_vals),
        'sev1_mttr_min': round(mean(
            i.mttr_minutes for i in incidents if i.severity == 'SEV-1'
        ), 1) if any(i.severity == 'SEV-1' for i in incidents) else None,
    }


if __name__ == '__main__':
    def dt(s): return datetime.fromisoformat(s)

    incidents = [
        IncidentTimeline('INC-40', 'SEV-2',
                         dt('2026-07-01T02:00'), dt('2026-07-01T02:18'),
                         dt('2026-07-01T02:21'), dt('2026-07-01T03:05')),
        IncidentTimeline('INC-41', 'SEV-3',
                         dt('2026-07-05T14:00'), dt('2026-07-05T14:08'),
                         dt('2026-07-05T14:15'), dt('2026-07-05T14:45')),
        IncidentTimeline('INC-42', 'SEV-1',
                         dt('2026-07-10T08:00'), dt('2026-07-10T08:05'),
                         dt('2026-07-10T08:08'), dt('2026-07-10T09:30')),
    ]

    report = compute_mttx_report(incidents, 'July 2026')
    print(json.dumps(report, indent=2))
